'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { 
  LayoutDashboard, 
  Users, 
  MessageSquare, 
  History, 
  Wrench, 
  LogOut,
  ChevronDown,
  Loader2
} from 'lucide-react';
import { cn } from '@/lib/utils';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { useUser, useAuth } from '@/firebase';
import { signOut } from 'firebase/auth';

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const router = useRouter();
  const auth = useAuth();
  const { user, isUserLoading } = useUser();
  const [isAuthorized, setIsAuthorized] = useState(false);

  useEffect(() => {
    if (isUserLoading) return;

    const isAdmin = localStorage.getItem('isAdmin');
    if (isAdmin !== 'true') {
      router.push('/login');
    } else if (!user) {
      // If the admin is not signed in to Firebase (session expired or not initialized)
      // but localStorage says they are admin, redirect to login to re-authenticate.
      router.push('/login');
    } else {
      setIsAuthorized(true);
    }
  }, [user, isUserLoading, router]);

  const handleLogout = async () => {
    localStorage.removeItem('isAdmin');
    await signOut(auth);
    router.push('/login');
  };

  if (isUserLoading || !isAuthorized) {
    return (
      <div className="flex h-screen items-center justify-center bg-[#F0F4F8]">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  const navLinks = [
    { href: '/admin/dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { href: '/admin/users', label: 'Users', icon: Users },
    { href: '/admin/feedback', label: 'Feedback', icon: MessageSquare },
    { href: '/admin/email-history', label: 'Email History', icon: History },
    { href: '/admin/tools', label: 'Tools', icon: Wrench, hasSub: true },
  ];

  return (
    <div className="min-h-screen bg-[#F0F4F8] flex flex-col">
      {/* Top Green Stripe */}
      <div className="h-1.5 w-full bg-[#064e3b]" />

      {/* Admin Header */}
      <header className="bg-[#1e293b] text-white shadow-md">
        <div className="container mx-auto px-4 h-14 flex items-center justify-between">
          <div className="flex items-center gap-8">
            <Link href="/admin/dashboard" className="flex items-center gap-2">
              <div className="w-6 h-6 bg-white rounded-md flex items-center justify-center">
                <div className="w-4 h-4 bg-[#1e293b] rounded-sm" />
              </div>
              <span className="font-bold text-sm tracking-tight whitespace-nowrap">Wallet Tally Admin</span>
            </Link>

            <nav className="hidden md:flex items-center gap-1">
              {navLinks.map((link) => (
                <Link
                  key={link.href}
                  href={link.href}
                  className="flex items-center gap-2 px-3 py-1.5 rounded-md hover:bg-white/10 transition-colors text-xs font-medium"
                >
                  <link.icon className="w-3.5 h-3.5" />
                  {link.label}
                  {link.hasSub && <ChevronDown className="w-3 h-3 ml-0.5 opacity-50" />}
                </Link>
              ))}
            </nav>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2.5 pl-4 border-l border-white/10">
              <Avatar className="h-7 w-7 border border-white/20">
                <AvatarImage src="https://api.dicebear.com/9.x/lorelei/svg?seed=Aiden" />
                <AvatarFallback>AD</AvatarFallback>
              </Avatar>
              <div className="hidden lg:block text-right">
                <p className="text-[10px] font-bold leading-none">WalletTallyAdmin</p>
                <p className="text-[9px] text-white/50 leading-none mt-1">Administrator</p>
              </div>
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button variant="ghost" size="icon" className="h-6 w-6 text-white/50 hover:text-white hover:bg-white/10">
                    <ChevronDown className="w-3.5 h-3.5" />
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent align="end" className="w-40 rounded-xl">
                  <DropdownMenuItem onClick={handleLogout} className="text-red-500 font-bold focus:text-red-500 focus:bg-red-50 cursor-pointer">
                    <LogOut className="w-4 h-4 mr-2" /> Logout
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 container mx-auto p-4 md:p-6 lg:p-8 space-y-6">
        <div className="space-y-1">
          <h1 className="text-xl font-bold text-[#1e293b]">Dashboard</h1>
          <p className="text-[11px] text-muted-foreground">Welcome back, <span className="font-bold text-primary">WalletTallyAdmin!</span></p>
        </div>
        {children}
      </main>
    </div>
  );
}
